INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Grafana Loki added to directory', '"Prometheus for logs." Indexes metadata (labels) not full text, making it cost-effective at scale. Alerting rules can fire on log patterns (error spikes, new exception types). Pairs with Promtail or Grafana Agent for log collection.', '9dd68437-d008-469f-b09d-2d756b82376d', 'new-tool', '2026-03-29 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('GitHub (official) added to directory', 'Repository operations, issues, PRs, code search, Actions', '15666c33-9d50-4f7d-8bc4-3c3ac2c99503', 'new-tool', '2026-03-29 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`playwright` added to directory', 'Microsoft''s browser automation MCP server. Claude controls Chrome to interact with web pages, take screenshots, fill forms, automate E2E testing.', '5255210a-574f-422b-9d75-6fd6e24d50f3', 'new-tool', '2026-03-29 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Design System Compliance Checker (Figma Plugin) added to directory', 'Figma plugin that audits design files for consistent use of design system styles and components.', 'cd14c497-e5b3-4212-91de-d78796d91cb1', 'new-tool', '2026-03-28 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('UI Automation Verify (UIA Verify) added to directory', 'Windows SDK framework for manual and automated testing of UIA implementations.', '2284747e-781d-49d0-9364-dd1893cb32f8', 'new-tool', '2026-03-28 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Radix UI Primitives added to directory', 'Unstyled, accessible React component primitives. Handles ARIA, keyboard navigation, and focus management. The foundation under shadcn/ui.', '45486770-2508-419e-8744-3a2350c2287a', 'new-tool', '2026-03-28 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('JUnit 5 added to directory', 'Standard Java testing framework. Annotations, parameterized tests, extensions.', 'ff1c7b13-417e-4658-b1e7-dc4ed7a02165', 'new-tool', '2026-03-28 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('nbformat added to directory', 'Programmatic notebook manipulation library. Create, modify, and validate `.ipynb` files from Python. The canonical API for notebook structure -- more stable than parsing JSON directly.', '7e6f26af-c2eb-44be-bacb-37dfe619f291', 'new-tool', '2026-03-27 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`ralph-loop` added to directory', 'Interactive AI loops for iterative development. Claude works on tasks repeatedly, seeing prior work until completion. Enables autonomous multi-hour coding sessions with context reset between tasks. Anthropic-verified.', '4c9f97f7-a2d4-4f98-804f-d3e5bb488fa7', 'new-tool', '2026-03-27 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Espresso added to directory', 'Google''s UI testing framework for Android Views (2013+). Three core components: `ViewMatchers` (find views: `withId()`, `withText()`, `withTagKey()`), `ViewActions` (perform actions: `click()`, `longClick()`, `scrollTo()`, `typeText()`), `ViewAssertions` (verify state: `matches()`, `doesNotExist()`)', 'ac354273-908b-4853-9c92-e14651ac3e88', 'new-tool', '2026-03-27 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('InSpec added to directory', 'Chef''s infrastructure testing framework for security compliance and system state verification. Write human-readable tests ("describe" blocks) that assert properties of OS packages, files, services, ports, cloud resources, and more. Supports AWS, Azure, GCP resource packs.', 'd80574cf-5443-4220-8de7-52852b642b9a', 'new-tool', '2026-03-27 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Permit.io added to directory', 'Authorization-as-a-service platform built on open-source tools (OPA, OPAL). Provides a UI for managing RBAC/ABAC policies.', '6292f175-f3bc-4643-9292-db91c34698bc', 'new-tool', '2026-03-26 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Unit tests added to directory', 'JUnit 5 + MockK', '6961748a-6bfa-4432-a058-0d81706ca4f4', 'new-tool', '2026-03-26 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Tailor added to directory', 'Cross-platform static analyzer and linter for Swift. Written in Java. Supports Swift 2.x/3.x. **Effectively unmaintained** -- last meaningful updates targeted Swift 3.0. Not recommended for new projects; included for historical reference. SwiftLint has fully superseded it.', '9107ea36-5c09-4ad1-bafc-72743f78b3e7', 'new-tool', '2026-03-26 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('structlog added to directory', 'Python structured logging library. Processes log entries through a pipeline of processors. Integrates with Sentry via structlog-sentry.', 'c335b17a-699d-4e3b-a00d-87a0dcb3c054', 'new-tool', '2026-03-26 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Prometheus added to directory', 'Open-source metrics collection and alerting. CNCF graduated project, de facto standard for Kubernetes monitoring.', 'dfc76ad4-d762-4cba-b250-dfb08a33eb31', 'new-tool', '2026-03-25 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('pg_stat_monitor added to directory', 'Percona''s enhanced alternative to pg_stat_statements. Includes actual query plans and more detailed grouping. PostgreSQL 14+.', '139354aa-d969-4191-bf54-0771c3c86e0d', 'new-tool', '2026-03-25 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`deliver` added to directory', 'Upload to App Store Connect', '9d6bcefe-b5a0-4767-b788-1a2420a4e73a', 'new-tool', '2026-03-25 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Claude Marketplaces added to directory', '[claudemarketplaces.com](https://claudemarketplaces.com/)', '322b7ef1-f7b8-4566-903c-8dc8fbd1c554', 'new-tool', '2026-03-25 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('envalid added to directory', 'Node.js runtime environment variable validation. Defines a schema for required vars with types, defaults, and descriptions. Fails fast at startup with clear error messages if vars are missing or malformed.', 'c03e8e74-c5e2-41b5-bd55-a22cfc0b0b2f', 'new-tool', '2026-03-24 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Dagger / Hilt added to directory', '*What it does: Compile-time dependency injection framework for Android. Hilt is the opinionated Android layer over Dagger. Supports KSP since Hilt 2.48, with current version at 2.57.1. KSP processing is up to 2x faster than kapt.', 'f9aa59e8-3004-467c-aed1-21f61b707e55', 'new-tool', '2026-03-24 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Visual Studio Application Timeline added to directory', 'Built-in Visual Studio profiler for XAML app resource consumption. Replaced the older "XAML UI Responsiveness" tool.', 'ca8b094e-efef-434b-91c4-de0ffe9a0dbd', 'new-tool', '2026-03-24 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('pg_isready added to directory', 'PostgreSQL connection checker. Returns exit code 0 if the server is accepting connections. Works with connection strings, supports timeout.', '030a0834-603e-45e4-8d66-6de08b1d4477', 'new-tool', '2026-03-24 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`adspirer-ads-agent` added to directory', 'Cross-platform ad management (Google, Meta, TikTok).', 'b869c1c1-ce36-42b2-9bff-b17a4ef0dc81', 'new-tool', '2026-03-23 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('neo-blessed added to directory', 'Community fork of blessed. Widget-based TUI with layouts, mouse support, and terminal abstraction. Less actively maintained than Ink but offers a broader widget set.', '6aa87f5b-6865-4d2f-9b58-64b6bf23e74e', 'new-tool', '2026-03-23 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`netlify-skills` added to directory', 'Netlify platform: serverless functions, edge computing, managed databases, image optimization, forms.', 'cdf20aea-0fcb-47c0-86c3-58a6c846dce3', 'new-tool', '2026-03-23 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`sales` added to directory', 'Prospect research, call prep, pipeline review, outreach drafts, battlecards', 'd642e1ff-b452-42d7-a1e8-67f224ed3080', 'new-tool', '2026-03-23 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`fiftyone` added to directory', 'Computer vision dataset building and management.', '14241a03-d6cc-4f3a-b02a-a33a9a073674', 'new-tool', '2026-03-22 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Figma Design System Compliance Checker added to directory', 'Figma plugin that audits design files for consistency with design system variables. Checks that designs use proper tokens (colors, spacing, typography) rather than hardcoded values. Works with Figma''s variables system.', '15d56980-435b-4819-be93-837bcc091560', 'new-tool', '2026-03-22 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('TypeORM added to directory', 'Decorator-based ORM for TypeScript supporting Active Record and Data Mapper patterns. Supports MySQL, PostgreSQL, SQLite, MSSQL, Oracle.', '9c538e9c-6855-4121-96bd-346a9277ce19', 'new-tool', '2026-03-22 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Rspack added to directory', 'Drop-in webpack replacement written in Rust. 10-23x faster than webpack 5 with ~85% webpack ecosystem compatibility (loaders, plugins).', 'b2d32709-e9f7-444d-9790-43234a867b4e', 'new-tool', '2026-03-22 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Playwright Test Runner added to directory', 'End-to-end testing framework with cross-browser support (Chromium, Firefox, WebKit). Auto-waiting, trace recording, and parallel test execution.', '119c7327-0980-47fc-9c74-2f3ae5610436', 'new-tool', '2026-03-21 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('General CLI Integration added to directory', 'Claude Code can invoke any CLI tool directly via its Bash tool. All tools in this catalog that have a command-line interface can be used by Claude Code without an MCP server. MCP servers add richer tool descriptions and structured interactions but are not required for basic usage.', 'd7607db3-4a11-4ab0-b929-5d7563e5c6f9', 'new-tool', '2026-03-21 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('tui-test added to directory', 'End-to-end terminal testing framework by Microsoft. Snapshot comparison, element visibility assertions, color assertions. Cross-platform (macOS, Linux, Windows) with multiple shell support.', 'bd143fc9-5098-4f80-a0b7-9f1da0f72456', 'new-tool', '2026-03-21 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('mysql added to directory', 'MySQL command-line client. Query execution, schema inspection, database administration.', '666b6bf3-d0e5-4383-8a51-333a8f23c9d5', 'new-tool', '2026-03-21 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('jq added to directory', 'Lightweight CLI JSON processor. Essential for parsing structured log output, API responses, and configuration files.', '879d6188-dd0e-494b-bc28-33bafa659071', 'new-tool', '2026-03-20 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Vitest added to directory', 'Fast test runner for Vite projects. Native ESM/TypeScript, 4x faster cold runs and 30% less memory than Jest. 400% adoption growth in 2023-2024.', 'cf364994-94a2-4164-88be-0af42a9a7daa', 'new-tool', '2026-03-20 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('pexpect added to directory', 'Python module for controlling interactive programs in a pseudo-terminal. Spawn a process, send input, wait for expected output patterns. The Python equivalent of TCL Expect.', '8c05a099-5fd4-4cbb-90a6-13ff9561da7a', 'new-tool', '2026-03-20 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('dotnet-monitor added to directory', 'Sidecar diagnostic tool that exposes REST APIs for collecting traces, dumps, counters, and logs from running .NET apps. Designed for containerized/production environments.', '6822acb7-f952-4229-8b89-d52732045659', 'new-tool', '2026-03-20 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('xcparse added to directory', 'Command-line tool for extracting screenshots and code coverage data from Xcode `.xcresult` bundles. Essential for CI pipelines that need to post-process test screenshots.', 'b32c1bdd-a18b-4fe2-848a-fc1dd423d6e8', 'new-tool', '2026-03-19 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('express-rate-limit added to directory', 'Basic rate-limiting middleware for Express. In-memory by default, supports Redis and other stores.', 'c136fd21-94b5-4767-9138-45e4a7a77d2f', 'new-tool', '2026-03-19 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('DocC added to directory', 'Apple''s documentation compiler for Swift frameworks and packages. Generates rich API reference documentation and interactive tutorials from doc comments and markdown articles. Powers most of Apple''s developer documentation. Supports customizable symbol access levels, C/C++/Objective-C targets, and s', '61a8df50-0a23-4968-8174-3be52aa6639e', 'new-tool', '2026-03-19 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('SecurityCodeScan added to directory', 'Vulnerability pattern detector for C# and VB.NET. Detects SQL injection, XSS, CSRF, XXE, and other OWASP Top 10 issues.', '7892a1f3-33f3-45c5-9f91-631339f36a04', 'new-tool', '2026-03-19 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`tap` added to directory', 'Tap at x,y coordinates', 'fd5bde3e-dab0-4154-a6a0-d45cb5b28c72', 'new-tool', '2026-03-18 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('AutoFixture added to directory', 'Automatic test object creation. Generates anonymous instances of any class, filling properties with random but valid data. Integrates with xUnit, NUnit, NSubstitute, Moq.', 'aadfb32e-d636-4249-bd8e-0b8b05ba2511', 'new-tool', '2026-03-18 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`produce` added to directory', 'Create new app on App Store Connect', 'b57268eb-81c3-417e-b51b-99fbf3e2c270', 'new-tool', '2026-03-18 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`optibot` added to directory', 'Catches production-breaking bugs, business logic issues, and security vulnerabilities. Analyzes local changes, compares branches, and reviews patch files with line-specific feedback.', 'ae232e5d-6340-4826-b71d-8be98bbcf978', 'new-tool', '2026-03-18 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Tokens Studio added to directory', 'Syncs design tokens from Figma to code via GitHub/GitLab. Supports color, typography, spacing, border-radius, and shadow tokens. 264,000+ active users.', '7a02cc09-084c-4a31-9110-f27a99a135b0', 'new-tool', '2026-03-17 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('XAML Hot Reload added to directory', 'Incrementally updates XAML UI in a running WPF, UWP, WinUI 3, or MAUI app without restarting. Starting in Visual Studio 2022 v17.14 Preview 2, also available at design-time (not just during debugging).', 'a3b0011b-b4a0-4c05-a6ab-ae8534517ee4', 'new-tool', '2026-03-17 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Grafana added to directory', 'Visualization and alerting dashboard. Unified alerting supports Prometheus, Loki, and other data sources. Alert rules can trigger on metric thresholds, log patterns, or composite conditions.', 'd070700a-213c-4956-815f-65b578caa747', 'new-tool', '2026-03-17 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('SonarAnalyzer.CSharp added to directory', '380+ C# rules and 130+ VB.NET rules from SonarSource. Covers bugs, vulnerabilities, code smells, and security hotspots. Works standalone (NuGet) or with SonarQube/SonarCloud.', '69f19e1e-eefc-4381-945e-531e847d1d26', 'new-tool', '2026-03-17 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Socket added to directory', 'Supply-chain threat detection at install time. Detects malicious packages, typosquatting, and install scripts. Pairs with Dependabot or Snyk.', '86b7799e-d8c7-43e6-b4f8-e1083dd10aaa', 'new-tool', '2026-03-16 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`bazel` added to directory', 'implement, verify', 'c107cc88-19ba-43c7-b1cd-57681f59a2d2', 'new-tool', '2026-03-16 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`XCUIElementQuery` added to directory', 'Queries for elements by type, identifier, predicate, or index', '836a0b12-2cf1-496d-89b4-87ac3af50cc0', 'new-tool', '2026-03-16 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('pytest added to directory', 'The dominant Python testing framework. Rich plugin ecosystem, fixtures, parametrize, assertion introspection.', '840043cd-1588-4443-9521-1d76331b473a', 'new-tool', '2026-03-16 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Molecule added to directory', '(Also listed under Infrastructure Testing.) The standard testing framework for Ansible roles. Creates test instances, applies the role, checks idempotence, runs verifiers, and destroys instances. Supports Docker, Podman, Vagrant, and cloud drivers.', 'f318e204-5d85-4658-bb20-eb06cf8423e7', 'new-tool', '2026-03-15 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Neon added to directory', 'Serverless Postgres management and queries', 'f0f8042a-1ae5-4b4c-a9bb-2d09ec82a695', 'new-tool', '2026-03-15 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('deepchecks added to directory', 'ML validation suite: 40+ built-in checks for data integrity, train/test comparison, model performance, and feature drift. Automated version comparisons and root cause analysis. Separate monitoring package for production.', 'd4acd6c9-cebf-43fb-b723-14d76c2d3d06', 'new-tool', '2026-03-15 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('MLflow model validation added to directory', 'Model registry with validation workflows. Tag model versions with validation status, use aliases (champion/challenger) for deployment promotion. v3.0 extends to GenAI/agents. Integrates with Unity Catalog on Databricks.', '22f32334-cbf2-481a-a350-5cc08b585c7d', 'new-tool', '2026-03-15 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Cloudflare added to directory', 'Manage Workers, KV, R2, and other Cloudflare resources', '1183e41e-461b-41a1-9169-a30c7a625445', 'new-tool', '2026-03-14 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('insta added to directory', 'Snapshot testing library for Rust. Captures values as YAML/JSON/TOML snapshots, stores them alongside tests, and diffs on change. `cargo-insta` CLI for reviewing and accepting snapshots. `insta-cmd` extension for testing CLI output directly.', '1eff3aed-c3f2-4403-9441-18d50d708696', 'new-tool', '2026-03-14 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('kapt added to directory', '*What it does: Kotlin Annotation Processing Tool. Generates Java stubs from Kotlin code, then runs Java annotation processors against those stubs. Slower than KSP because of the stub generation step. Now in maintenance mode — migrate to KSP when processors support it.', '12218720-217a-468b-850c-4c43bc65e5cb', 'new-tool', '2026-03-14 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Docker MCP Catalog added to directory', '[hub.docker.com/mcp](https://hub.docker.com/search?q=mcp)', 'caf383a4-a02b-4371-a2bc-6d7b9ec21701', 'new-tool', '2026-03-14 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('NuGet Audit added to directory', 'Automatic vulnerability scanning during `dotnet restore`. NuGet Audit 2.0 scans direct and transitive dependencies against the GitHub Advisory Database. In .NET 10+, audit mode defaults to "all" (direct + transitive).', '297ce13b-e54d-44de-9817-168b86c60d1d', 'new-tool', '2026-03-13 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Auth.js added to directory', 'Framework-agnostic auth for Next.js, SvelteKit, etc. with 80+ OAuth providers. The established leader for Next.js authentication.', '55e8c905-fc06-42d3-81f3-411115133db0', 'new-tool', '2026-03-13 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('performAccessibilityAudit added to directory', 'Built-in XCTest method (Xcode 15+) that audits any `XCUIElement` for accessibility issues. Fails the test automatically when issues are found. Scoped audits let you check the entire app, a single screen, or an individual component.', '35b76b85-27e3-4bb3-b516-146b544b4801', 'new-tool', '2026-03-13 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('shadcn/ui added to directory', 'Copy-paste component collection built on Radix UI (or Base UI as of Feb 2026) and Tailwind CSS. Components live in your codebase, not node_modules. 75,000+ GitHub stars.', 'a02a6af2-984a-4c51-9807-daab3159f013', 'new-tool', '2026-03-13 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Plugin.Maui.UITestHelpers added to directory', 'Community NuGet package providing MAUI-specific UI test helper methods.', '9a8df000-d84b-42e7-8772-5ec4be0b9dda', 'new-tool', '2026-03-12 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`-scheme` added to directory', 'Build scheme name', '821a56d0-e193-4cd3-a35e-ab5fd152233c', 'new-tool', '2026-03-12 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`rust-analyzer-lsp` added to directory', 'Rust', '98b8ebb5-1c50-4316-9c53-fb86439b07a7', 'new-tool', '2026-03-12 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Postman added to directory', 'API collection and environment access from Postman workspaces', '845bf31f-e632-4a4a-979a-64cae8292a3e', 'new-tool', '2026-03-12 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('WWDC25: Record, Replay, and Review added to directory', 'New Xcode 17 UI automation features for recording, replaying, and reviewing UI interactions. Includes improved accessibility-driven automation and stable element identification for SwiftUI views.', 'd6d186ce-8a39-4fda-83f7-184fc2ef92dd', 'new-tool', '2026-03-11 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Source control added to directory', '**GitHub**', 'b63ad9e0-bff8-49ec-a980-119da1c6c9a8', 'new-tool', '2026-03-11 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('kubectl rollout added to directory', 'Built-in Kubernetes rollback commands. `kubectl rollout undo` reverts to the previous revision; `--to-revision=N` targets a specific revision. `kubectl rollout history` shows revision history. `kubectl rollout status` monitors progress.', 'e2e8710b-aa1d-4239-8efd-10c94f43259a', 'new-tool', '2026-03-11 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Cline added to directory', 'Claude, GPT, Gemini, Bedrock, local models', 'e14c4727-76fe-4d47-83e0-e8615fa6a4ee', 'new-tool', '2026-03-11 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Weights & Biases (W&B) added to directory', 'Developer-first experiment tracking with best-in-class visualization. Real-time dashboards, hyperparameter sweeps, artifact versioning, and team collaboration. Vertically integrated with CoreWeave GPU cloud. The default for teams prioritizing developer experience.', '99424859-de9a-4a24-9a62-2cff9c96da47', 'new-tool', '2026-03-10 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('PulseMCP added to directory', '[pulsemcp.com/servers](https://www.pulsemcp.com/servers)', '9f113707-5181-4ab2-b8e2-df7cb03ef873', 'new-tool', '2026-03-10 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Docker HEALTHCHECK added to directory', 'Built-in Docker instruction that runs a command inside the container at intervals to verify health. Combined with `depends_on: condition: service_healthy` in Compose, replaces external wait scripts entirely.', '9996d03b-bf05-445a-abfe-984741931094', 'new-tool', '2026-03-10 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`frameit` added to directory', 'Add device frames to screenshots', '22bdfad8-0996-49ae-91bd-2837b4ed3aa6', 'new-tool', '2026-03-10 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('kubectl MCP added to directory', 'kubectl wrapper for pod diagnostics, rollouts, resource inspection', '224ae9bc-e9d2-43d8-9b94-1257e3b4324b', 'new-tool', '2026-03-09 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('FlaUInspect added to directory', 'Visual inspection tool for exploring UI Automation trees of running Windows applications. The modern replacement for Inspect.exe.', 'f73ac59e-7ea6-49a6-b6ea-95ece59ba636', 'new-tool', '2026-03-09 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`sanity-plugin` added to directory', 'Sanity headless CMS content management.', '363b9793-3b16-4898-a811-0b7827d51b62', 'new-tool', '2026-03-09 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('AWS Lambda Tool added to directory', 'Execute Lambda functions as AI tools', '66f034c3-dd7d-46f4-9933-cae1da19501c', 'new-tool', '2026-03-09 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Layout Inspector added to directory', 'Android Studio tool that shows the Compose component tree with recomposition counts and skip counts for each node. Highlights actively recomposing nodes with a gradient overlay — higher recomposition rates show stronger highlighting. Helps visually identify which composables are recomposing unnecess', 'b8fea9cf-1d03-4cde-ae61-ff8b81c2b6fd', 'new-tool', '2026-03-08 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Gradle Version Catalog added to directory', '*What it does: Centralizes dependency versions in a single `libs.versions.toml` file. Generates type-safe accessors for all modules. Sections: `[versions]`, `[libraries]`, `[bundles]`, `[plugins]`. Eliminates version duplication across multi-module projects.', '94dc38d1-c88d-4a07-b7bf-85dcd64311e0', 'new-tool', '2026-03-08 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('SAST added to directory', 'Semgrep', 'af5f2a84-e0c5-4faa-8557-0e540c2a92b6', 'new-tool', '2026-03-08 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('bashate added to directory', 'Code style enforcement for bash, modeled on pycodestyle (PEP 8). Checks indentation, line length, and basic style rules.', 'e4c3cf18-4e9b-4584-8274-d45a24b5a0f5', 'new-tool', '2026-03-08 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Gitleaks added to directory', 'Fast regex-based secret scanner for Git repos. Best as a pre-commit hook -- blocks secrets in milliseconds. Lightweight and simple.', '41669e59-3fd6-4085-adc0-3230fc6a5813', 'new-tool', '2026-03-07 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Kotlin Language Server added to directory', 'Provides IDE-level code intelligence for Kotlin in Claude Code: go-to-definition, find-references, hover documentation, document symbols, and diagnostics. Released December 2025.', '5c6cf06c-cc42-4c5f-bc84-af97bf6084d7', 'new-tool', '2026-03-07 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Android Emulator added to directory', 'The Android Emulator simulates Android devices on your computer. It supports snapshots, GPU acceleration, network simulation, and headless mode for CI.', '4c624e32-aba1-4b7b-8dda-8d16d7e9fde0', 'new-tool', '2026-03-07 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Core Build Commands added to directory', 'The Android Gradle Plugin (AGP) is the standard build system for Android. All builds are invoked via the Gradle wrapper (`./gradlew` on macOS/Linux, `gradlew` on Windows). Commands follow camelCase variant naming: `assemble{Flavor}{BuildType}`.', '1754a16b-8af9-449c-b805-ed3921db5156', 'new-tool', '2026-03-07 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('web-vitals added to directory', 'Tiny library (1.5KB) for measuring Core Web Vitals (LCP, CLS, INP, FCP, TTFB) in the browser. Reports real user metrics.', '48d86514-5f62-400b-8697-0ee9feb8c727', 'new-tool', '2026-03-06 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('xctrace added to directory', 'Profiling', '56b4be1a-f750-4282-a300-00618ce14a38', 'new-tool', '2026-03-06 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Grafana Synthetic Monitoring added to directory', 'Proactive endpoint monitoring using Prometheus Blackbox exporter probes. Pre-configured sensitivity tiers: High (5% probe failure for 5m), Medium (10%), Low (25%). Available in Grafana Cloud with configurable check types (HTTP, DNS, TCP, ping).', 'f8be6277-28bf-44f5-9734-1287087497e1', 'new-tool', '2026-03-06 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Supertest added to directory', 'HTTP assertion library for Node.js. Test Express/Fastify/Koa endpoints without starting a server. Pairs with Jest or Vitest.', '024abaf4-d41b-410c-acac-7a53f5b4c5bc', 'new-tool', '2026-03-06 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('OpenTofu added to directory', 'Community-driven, open-source fork of Terraform under the Linux Foundation. Drop-in compatible with Terraform 1.5.x. All major Terraform ecosystem tools (TFLint, Checkov, Infracost, Terragrunt) work with OpenTofu.', '8ac3a622-5083-4198-80c9-32a05c9aaa57', 'new-tool', '2026-03-05 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`-enableCodeCoverage YES` added to directory', 'Enable code coverage collection', 'b8949de4-ad41-4122-9ea5-b1d3a63b3cee', 'new-tool', '2026-03-05 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('dotnet new (templates) added to directory', 'Project and item scaffolding. Built-in templates for webapi, console, classlib, blazor, etc. Custom templates via `template.json`.', '3bf5b6b0-d086-4878-b533-fe53fc7e71d5', 'new-tool', '2026-03-05 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('MCP Servers for Android added to directory', 'Platform-agnostic MCP server for both Android and iOS automation. Provides device management, app management, screen interaction (tap, swipe, type), screenshot capture, and element inspection.', '804248cf-0c31-41f5-b078-894436451dfb', 'new-tool', '2026-03-05 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('env-sentinel added to directory', 'Environment variable management and validation platform. Three-layer merge (base, environment-specific, personal overrides). Startup validation with format checking.', 'd51599bf-cf2a-4cb3-b6b8-80d3e1145fa7', 'new-tool', '2026-03-04 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Homebrew Tap added to directory', 'Create a custom Homebrew tap repository (`homebrew-tap`) with formula files. Users install via `brew install user/tap/tool`. Works for any language that produces binaries.', '03783ba2-06a5-4c8e-8bf0-d5717b859d0e', 'new-tool', '2026-03-04 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`security-guidance` added to directory', 'Hook that intercepts file writes and scans for 8 vulnerability categories (injection, XSS, unsafe code evaluation, dangerous deserialization, shell command risks, etc.) before changes are applied.', 'b3256c8c-d4cd-4414-95fd-2b6d06f83bf9', 'new-tool', '2026-03-04 09:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Firebase Auth added to directory', 'Google-hosted auth with email/password, phone, and social providers. Tight integration with other Firebase services.', 'd3615968-7ccc-4bf3-a1cc-1f385129510e', 'new-tool', '2026-03-04 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Amazon Q Developer added to directory', 'Claude 3.5 Sonnet, Bedrock models (auto-selected)', '93420fa5-0b65-47bb-b598-2f3387658f81', 'new-tool', '2026-03-03 21:55:07');
