INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`product-tracking-skills` added to directory', 'Product analytics instrumentation.', 'db64a312-2622-466a-8711-090ac4d2dd23', 'new-tool', '2026-03-02 21:55:07');
