INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Marshmallow added to directory', 'Python library for object serialization/deserialization and validation. v4.1 current. Flask-Marshmallow for Flask integration.', '8ae41d06-10da-4ad7-bd61-62fc9861c146', 'new-tool', '2026-03-01 21:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`vercel` added to directory', 'Vercel deployment platform integration. Deploy frontends and serverless functions.', '7ecad3fb-e639-4232-a18e-89ecae1fcdca', 'new-tool', '2026-03-01 15:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('Mint added to directory', 'Package manager for installing and running Swift CLI tools. Installs executables from any Swift package with an executable target. Supports multiple versions side-by-side. Central cache. Version 0.18.x is current. Ideal for managing project-specific tool versions (SwiftLint, SwiftFormat, Sourcery, e', '54af004f-68f2-4e4c-af62-3e5002ebca91', 'new-tool', '2026-03-01 09:55:07');
