INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`supabase` added to directory', 'Supabase backend services: database, auth, storage, real-time subscriptions, edge functions.', 'db7bec74-2ec7-431d-95b0-dab826470703', 'new-tool', '2026-02-28 21:55:07');
