INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('rate-limit-redis added to directory', 'Redis store for express-rate-limit. Also supports Redict and Valkey.', 'b58ac4f2-0540-4226-82ac-33d412882dac', 'new-tool', '2026-02-28 03:55:07');
INSERT INTO news (title, body, tool_id, type, published_at) VALUES ('`neon` added to directory', 'Neon PostgreSQL database management. Neon-specific skills and API access via MCP server.', '549b6882-c95d-4285-bbaf-69a8d8c731e3', 'new-tool', '2026-02-27 21:55:07');